com.mirth.connect.plugins.javascriptstep.script:
// ---- Patient fields ----
var patientId, patientName, testName, resultValue, resultStatus, abnormalFlag, units;

try { patientId = msg['PID']['PID.3']['PID.3.1'].toString(); } catch(e) { patientId = 'UNKNOWN'; logger.error('Missing PID.3.1: ' + e.message); }
try { patientName = msg['PID']['PID.5']['PID.5.2'].toString() + ' ' + msg['PID']['PID.5']['PID.5.1'].toString(); } catch(e) { patientName = 'UNKNOWN'; logger.error('Missing PID.5: ' + e.message); }
try { testName = msg['OBX']['OBX.3']['OBX.3.2'].toString(); } catch(e) { testName = 'UNKNOWN'; logger.error('Missing OBX.3.2: ' + e.message); }
try { resultValue = msg['OBX']['OBX.5']['OBX.5.1'].toString(); } catch(e) { resultValue = ''; logger.error('Missing OBX.5.1: ' + e.message); }
try { abnormalFlag = msg['OBX']['OBX.8']['OBX.8.1'].toString(); } catch(e) { abnormalFlag = 'N'; logger.error('Missing OBX.8.1: ' + e.message); }
try { resultStatus = msg['OBX']['OBX.11']['OBX.11.1'].toString(); } catch(e) { resultStatus = 'UNKNOWN'; logger.error('Missing OBX.11.1: ' + e.message); }
try { units = msg['OBX']['OBX.6']['OBX.6.1'].toString(); } catch(e) { units = ''; logger.error('Missing OBX.6.1: ' + e.message); }

// ---- Mid-flight provider lookup ----
var orderingProvider = 'UNKNOWN';
var providerSpecialty = 'UNKNOWN';
try {
    var npi = msg['OBR']['OBR.16']['OBR.16.1'].toString();
    logger.info('OBR segment: ' + msg['OBR'].toString());
    logger.info('NPI extracted: [' + npi + ']');
    var dbConn = DatabaseConnectionFactory.createDatabaseConnection('org.postgresql.Driver', 'jdbc:postgresql://${DB_HOST}:${DB_PORT}/bridgelink_db', '${DB_USERNAME}', '${DB_PASSWORD}');
    var result = dbConn.executeCachedQuery("SELECT first_name, last_name, specialty FROM providers WHERE npi = '" + npi + "'");
    if (result.next()) {
        orderingProvider = result.getString('first_name') + ' ' + result.getString('last_name');
        providerSpecialty = result.getString('specialty');
    }
    dbConn.close();
} catch(e) {
    logger.error('Provider lookup failed: ' + e.message);
}

// ---- Cross-channel patient lookup ----
var admissionStatus = 'UNKNOWN';
try {
    var patDbConn = DatabaseConnectionFactory.createDatabaseConnection('org.postgresql.Driver', 'jdbc:postgresql://${DB_HOST}:${DB_PORT}/bridgelink_db', '${DB_USERNAME}', '${DB_PASSWORD}');
    var patResult = patDbConn.executeCachedQuery("SELECT admission_status FROM patients WHERE patient_id = '" + patientId + "'");
    if (patResult.next()) {
        admissionStatus = patResult.getString('admission_status');
    }
    patDbConn.close();
} catch(e) {
    logger.error('Patient lookup failed: ' + e.message);
}

channelMap.put('admission_status', admissionStatus);
channelMap.put('patient_id', patientId);
channelMap.put('patient_name', patientName);
channelMap.put('test_name', testName);
channelMap.put('result_value', resultValue);
channelMap.put('result_status', resultStatus);
channelMap.put('abnormal_flag', abnormalFlag);
channelMap.put('units', units);
channelMap.put('ordering_provider', orderingProvider);
channelMap.put('provider_specialty', providerSpecialty);

// ---- Error-safe field extraction ----
var patientId, patientName, testName, resultValue, resultStatus, abnormalFlag, units;

try { patientId = msg['PID']['PID.3']['PID.3.1'].toString(); } catch(e) { patientId = 'UNKNOWN'; logger.error('Missing PID.3.1: ' + e.message); }
try { patientName = msg['PID']['PID.5']['PID.5.2'].toString() + ' ' + msg['PID']['PID.5']['PID.5.1'].toString(); } catch(e) { patientName = 'UNKNOWN'; logger.error('Missing PID.5: ' + e.message); }
try { testName = msg['OBX']['OBX.3']['OBX.3.2'].toString(); } catch(e) { testName = 'UNKNOWN'; logger.error('Missing OBX.3.2: ' + e.message); }
try { resultValue = msg['OBX']['OBX.5']['OBX.5.1'].toString(); } catch(e) { resultValue = ''; logger.error('Missing OBX.5.1: ' + e.message); }
try { abnormalFlag = msg['OBX']['OBX.8']['OBX.8.1'].toString(); } catch(e) { abnormalFlag = 'N'; logger.error('Missing OBX.8.1: ' + e.message); }
try { resultStatus = msg['OBX']['OBX.11']['OBX.11.1'].toString(); } catch(e) { resultStatus = 'UNKNOWN'; logger.error('Missing OBX.11.1: ' + e.message); }
try { units = msg['OBX']['OBX.6']['OBX.6.1'].toString(); } catch(e) { units = ''; logger.error('Missing OBX.6.1: ' + e.message); }

// ---- Mid-flight provider lookup ----
var orderingProvider = 'UNKNOWN';
var providerSpecialty = 'UNKNOWN';
try {
    var npi = msg['OBR']['OBR.16']['OBR.16.1'].toString();
    var dbConn = DatabaseConnectionFactory.createDatabaseConnection('org.postgresql.Driver', 'jdbc:postgresql://${DB_HOST}:${DB_PORT}/bridgelink_db', '${DB_USERNAME}', '${DB_PASSWORD}');
    var result = dbConn.executeCachedQuery("SELECT first_name, last_name, specialty FROM providers WHERE npi = '" + npi + "'");
    if (result.next()) {
        orderingProvider = result.getString('first_name') + ' ' + result.getString('last_name');
        providerSpecialty = result.getString('specialty');
    }
    dbConn.close();
} catch(e) {
    logger.error('Provider lookup failed: ' + e.message);
}

// ---- Cross-channel patient lookup ----
var admissionStatus = 'UNKNOWN';
try {
    var patDbConn = DatabaseConnectionFactory.createDatabaseConnection('org.postgresql.Driver', 'jdbc:postgresql://${DB_HOST}:${DB_PORT}/bridgelink_db', '${DB_USERNAME}', '${DB_PASSWORD}');
    var patResult = patDbConn.executeCachedQuery("SELECT admission_status FROM patients WHERE patient_id = '" + patientId + "'");
    if (patResult.next()) {
        admissionStatus = patResult.getString('admission_status');
    }
    patDbConn.close();
} catch(e) {
    logger.error('Patient lookup failed: ' + e.message);
}

channelMap.put('patient_id', patientId);
channelMap.put('patient_name', patientName);
channelMap.put('test_name', testName);
channelMap.put('result_value', resultValue);
channelMap.put('result_status', resultStatus);
channelMap.put('abnormal_flag', abnormalFlag);
channelMap.put('units', units);
channelMap.put('ordering_provider', orderingProvider);
channelMap.put('provider_specialty', providerSpecialty);
channelMap.put('admission_status', admissionStatus);

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
